import { defineConfig, devices } from '@playwright/test';

export default defineConfig({
  testDir: './tests',
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: 'html',
  use: {
    baseURL: 'http://127.0.0.1:3000',
    trace: 'on-first-retry',
  },
  projects: [
    { name: 'chromium', use: { ...devices['Desktop Chrome'] } },
    { name: 'firefox', use: { ...devices['Desktop Firefox'] } },
    { name: 'webkit', use: { ...devices['Desktop Safari'] } },
  ],
});

import { test, expect } from '@playwright/test';

test('basic test', async ({ page }) => {
  await page.goto('https://playwright.dev/');
  await expect(page.getByRole('heading', { name: 'Playwright enables reliable end-to-end testing' })).toBeVisible();
});

// Get by role
const button = page.getByRole('button', { name: 'Submit' });

// Get by label
const input = page.getByLabel('Username');

// Get by placeholder
const search = page.getByPlaceholder('Search...');

// Get by test id
const element = page.getByTestId('checkout-button');

import { test, expect } from '@playwright/test';

test('assertions example', async ({ page }) => {
  await page.goto('https://playwright.dev/');

  // Auto-retrying assertions
  await expect(page.getByText('Get started')).toBeVisible();
  await expect(page).toHaveTitle(/Playwright/);

  // Soft assertions
  await expect.soft(page.getByTestId('status')).toHaveText('Success');

  // Non-retrying assertion
  expect(1 + 1).toBe(2);
});

